import React, { useState, useRef, useEffect } from 'react';
// Import the Google AI SDK
import { GoogleGenerativeAI } from "@google/generative-ai";

// 🔑 YOUR NEW API KEY IS INTEGRATED HERE
const API_KEY = "AIzaSyC35RtQVQDpvnavIumd3-Lkt0T8je5iI5w"; 

function ChatBot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { text: "👋 Hi! I'm CampusBot. Ask me about uploading projects, admin access, or any errors you are facing!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  // Auto-scroll to the bottom of the chat
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking]);

  // --- THE AI BRAIN ---
  const generateResponse = async (userQuestion) => {
    try {
      // 1. Initialize Google AI
      const genAI = new GoogleGenerativeAI(API_KEY);
      
      // 2. Select the "Flash" Model (Fastest & Most Reliable for Free Tier)
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

      // 3. Define the Bot's Knowledge (System Prompt)
      const systemContext = `
        You are "CampusBot", the intelligent assistant for the CampusCanvas project.
        
        PROJECT DETAILS:
        - **Goal:** A centralized repository for student projects.
        - **Tech Stack:** React.js (Frontend), Firebase (Backend), Tailwind CSS.
        - **Hosting:** Vercel.
        
        KEY RULES & FEATURES:
        - **Students:** Can upload projects (Title, Desc, Image, Category).
        - **Admins:** Can Approve or Reject submissions via the Dashboard.
        - **Upload Limit:** Images must be under 1MB.
        - **Storage:** Images are stored as Base64 strings (Text) in Firestore to avoid AWS costs.
        
        TROUBLESHOOTING GUIDE:
        - "White Screen": Usually a React crash. Refresh or check console for undefined variables.
        - "Slow Loading": Caused by decoding large Base64 image strings.
        - "Permission Denied": You are likely logged in as a Student, not an Admin.
        
        INSTRUCTIONS:
        - Keep answers short, friendly, and helpful.
        - If asked for code, provide small snippets.
      `;

      // 4. Send the Request
      const prompt = `${systemContext}\n\nUser Question: ${userQuestion}\nAnswer:`;
      const result = await model.generateContent(prompt);
      const response = await result.response;
      return response.text();

    } catch (error) {
      console.error("AI Error:", error);
      // Return a helpful error message to the chat window
      return `⚠️ Connection Error: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Show User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    // 2. Get AI Response
    const aiText = await generateResponse(input);

    // 3. Show AI Message
    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      
      {/* CHAT WINDOW */}
      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden animate-fade-in-up mb-4">
          
          {/* Header */}
          <div className="bg-indigo-600 p-4 flex justify-between items-center text-white shadow-md">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-1.5 rounded-full backdrop-blur-md">🤖</div>
              <div>
                <h3 className="font-bold text-sm">CampusBot</h3>
                <p className="text-[10px] text-indigo-200">Online • AI Powered</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-indigo-700 w-8 h-8 rounded-full transition">✕</button>
          </div>

          {/* Messages Area */}
          <div className="flex-1 p-4 overflow-y-auto bg-gray-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-xl text-sm leading-relaxed shadow-sm ${
                  msg.isBot 
                    ? 'bg-white border border-gray-200 text-gray-800 rounded-tl-none' 
                    : 'bg-indigo-600 text-white rounded-tr-none'
                }`}>
                  {/* Basic Code Block Formatting */}
                  {msg.text.split('```').map((part, i) => 
                    i % 2 === 1 ? (
                      <code key={i} className="block bg-black text-green-400 p-2 rounded text-xs my-2 overflow-x-auto font-mono">
                        {part}
                      </code>
                    ) : (
                      <span key={i}>{part}</span>
                    )
                  )}
                </div>
              </div>
            ))}
            
            {/* Thinking Animation */}
            {isThinking && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-200 p-3 rounded-xl rounded-tl-none shadow-sm flex gap-1">
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." 
              className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500 bg-gray-100 border border-transparent focus:bg-white transition"
            />
            <button 
              onClick={handleSend}
              disabled={isThinking}
              className={`w-10 h-10 rounded-full flex items-center justify-center transition shadow-md ${
                isThinking ? 'bg-gray-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white active:scale-95'
              }`}
            >
              ➤
            </button>
          </div>
        </div>
      )}

      {/* FLOATING BUTTON */}
      {!isOpen && (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full shadow-xl shadow-indigo-500/40 flex items-center justify-center text-3xl transition-transform hover:scale-110 active:scale-95"
        >
          🤖
        </button>
      )}
    </div>
  );
}

export default ChatBot;
